// Generic class — T is fixed per instance
class Stack<T> {
  private items: T[] = [];

  push(item: T): void     { this.items.push(item); }
  pop(): T | undefined    { return this.items.pop(); }
  peek(): T | undefined   { return this.items[this.items.length - 1]; }
  get size(): number      { return this.items.length; }
  isEmpty(): boolean      { return this.items.length === 0; }
}

const numStack = new Stack<number>();
numStack.push(1);
numStack.push(2);
console.log(numStack.pop()); // 2 — type: number

const strStack = new Stack<string>();
strStack.push('hello');
// strStack.push(42); // Error: Argument of type 'number' is not assignable to type 'string'

// Single type parameter
class Box<T> {
  constructor(public value: T) {}

  map<U>(fn: (v: T) => U): Box<U> {
    return new Box(fn(this.value));
  }
}

const strBox = new Box('hello');
const lenBox = strBox.map(s => s.length); // Box<number>

// Multiple type parameters
class Pair<A, B> {
  constructor(
    public first: A,
    public second: B,
  ) {}

  swap(): Pair<B, A> {
    return new Pair(this.second, this.first);
  }

  toTuple(): [A, B] {
    return [this.first, this.second];
  }
}

const p = new Pair('Alice', 42);
const swapped = p.swap();    // Pair<number, string>
const tuple   = p.toTuple(); // [string, number]

// Constrained type parameter
class SortedList<T extends { compareTo(other: T): number }> {
  private items: T[] = [];

  add(item: T): void {
    this.items.push(item);
    this.items.sort((a, b) => a.compareTo(b));
  }

  toArray(): T[] { return [...this.items]; }
}

class Container<T> {
  static count = 0;          // T is NOT available here — statics belong to the class, not instances
  value: T;                  // T is available on instance members

  constructor(value: T) {
    this.value = value;
    Container.count++;
  }

  // Static generic method — uses its OWN type parameter, not the class T
  static of<U>(value: U): Container<U> {
    return new Container(value);
  }
}

const c1 = new Container(1);       // Container<number>
const c2 = Container.of('hello'); // Container<string>
console.log(Container.count);      // 2 — static property shared across all instances

// Generic interface — implemented by a class or used as a type
interface Repository<T> {
  findById(id: number): Promise<T>;
  save(entity: T): Promise<T>;
  delete(id: number): Promise<void>;
  findAll(): Promise<T[]>;
}

// Implementing a generic interface — T is bound at the class declaration
class UserRepository implements Repository<User> {
  private users: User[] = [];

  async findById(id: number): Promise<User> {
    const user = this.users.find(u => u.id === id);
    if (!user) throw new Error(`User ${id} not found`);
    return user;
  }

  async save(user: User): Promise<User> {
    const idx = this.users.findIndex(u => u.id === user.id);
    if (idx >= 0) this.users[idx] = user;
    else           this.users.push(user);
    return user;
  }

  async delete(id: number): Promise<void> {
    this.users = this.users.filter(u => u.id !== id);
  }

  async findAll(): Promise<User[]> { return [...this.users]; }
}

