// Use a generic interface as a variable type
interface EventEmitter<Events extends Record<string, unknown>> {
  on<K extends keyof Events>(event: K, handler: (data: Events[K]) => void): void;
  off<K extends keyof Events>(event: K, handler: (data: Events[K]) => void): void;
  emit<K extends keyof Events>(event: K, data: Events[K]): void;
}

// Specify the event map when using the interface as a type
type AppEvents = {
  userLogin:  { userId: number; timestamp: Date };
  pageView:   { path: string };
  orderPlace: { orderId: string; total: number };
};

function createEmitter<E extends Record<string, unknown>>(): EventEmitter<E> {
  const handlers = new Map<keyof E, Set<Function>>();
  return {
    on:   (event, handler) => { /* ... */ },
    off:  (event, handler) => { /* ... */ },
    emit: (event, data)    => { /* ... */ },
  };
}

const bus = createEmitter<AppEvents>();
bus.on('userLogin', ({ userId, timestamp }) => {
  // userId: number, timestamp: Date — fully typed
  console.log(`User ${userId} logged in at ${timestamp.toISOString()}`);
});
bus.emit('userLogin', { userId: 1, timestamp: new Date() }); // OK
// bus.emit('userLogin', { userId: 'wrong' }); // Error: string is not number

interface HasId { id: number }

// T must have an id field — constraint enables safe key access inside the class
class EntityMap<T extends HasId> {
  private map = new Map<number, T>();

  set(entity: T): void {
    this.map.set(entity.id, entity);
  }

  get(id: number): T | undefined {
    return this.map.get(id);
  }

  getAll(): T[] {
    return Array.from(this.map.values());
  }

  has(id: number): boolean {
    return this.map.has(id);
  }
}

interface Product { id: number; name: string; price: number }

const products = new EntityMap<Product>();
products.set({ id: 1, name: 'Widget', price: 9.99 });
products.set({ id: 2, name: 'Gadget', price: 24.99 });
console.log(products.get(1)?.name); // 'Widget'

// Default type parameter — used when no argument is given
interface ApiResponse<T = unknown> {
  data: T;
  status: number;
  message: string;
}

// With default — T = unknown
const raw: ApiResponse = { data: {}, status: 200, message: 'ok' };

// With explicit type
const typed: ApiResponse<User[]> = { data: [], status: 200, message: 'ok' };

// Default on a class
class Cache<K = string, V = unknown> {
  private store = new Map<K, V>();

  set(key: K, value: V): void { this.store.set(key, value); }
  get(key: K): V | undefined  { return this.store.get(key); }
}

const c1 = new Cache();              // Cache<string, unknown>
const c2 = new Cache<string, User>(); // Cache<string, User>

import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';
import { map } from 'rxjs/operators';
import { Signal, signal, computed } from '@angular/core';

// Generic CRUD base — extend for each resource type
@Injectable()
abstract class CrudService<T extends { id: number }> {
  protected abstract readonly endpoint: string;
  protected readonly items = signal<T[]>([]);

  readonly count = computed(() => this.items().length);

  constructor(protected http: HttpClient) {}

  load(): Observable<T[]> {
    return this.http.get<T[]>(this.endpoint).pipe(
      map(data => { this.items.set(data); return data; }),
    );
  }

  create(payload: Omit<T, 'id'>): Observable<T> {
    return this.http.post<T>(this.endpoint, payload).pipe(
      map(created => { this.items.update(list => [...list, created]); return created; }),
    );
  }

  update(id: number, patch: Partial<T>): Observable<T> {
    return this.http.patch<T>(`${this.endpoint}/${id}`, patch).pipe(
      map(updated => {
        this.items.update(list => list.map(item => item.id === id ? updated : item));
        return updated;
      }),
    );
  }

  remove(id: number): Observable<void> {
    return this.http.delete<void>(`${this.endpoint}/${id}`).pipe(
      map(() => { this.items.update(list => list.filter(item => item.id !== id)); }),
    );
  }
}

interface User { id: number; name: string; email: string }

@Injectable({ providedIn: 'root' })
class UserService extends CrudService<User> {
  protected readonly endpoint = '/api/users';
}

import { signal, computed, Signal } from '@angular/core';

interface StoreState<T> {
  items: T[];
  selected: T | null;
  loading: boolean;
  error: string | null;
}

// Generic reactive store — one class for every list-based feature
class ListStore<T extends { id: number }> {
  private readonly state = signal<StoreState<T>>({
    items: [],
    selected: null,
    loading: false,
    error: null,
  });

  readonly items    = computed(() => this.state().items);
  readonly selected = computed(() => this.state().selected);
  readonly loading  = computed(() => this.state().loading);
  readonly error    = computed(() => this.state().error);

  setItems(items: T[]): void {
    this.state.update(s => ({ ...s, items, loading: false }));
  }

  select(id: number): void {
    const found = this.state().items.find(item => item.id === id) ?? null;
    this.state.update(s => ({ ...s, selected: found }));
  }

  setLoading(): void { this.state.update(s => ({ ...s, loading: true, error: null })); }

  setError(msg: string): void {
    this.state.update(s => ({ ...s, loading: false, error: msg }));
  }
}

// Per-feature store — T is bound at declaration
const userStore    = new ListStore<User>();
const productStore = new ListStore<Product>();

interface Product { id: number; name: string; price: number }
interface User    { id: number; name: string; email: string }

// Extending a generic interface — the type parameter passes through
interface Identifiable { id: number }

interface Entity<T> extends Identifiable {
  data: T;
  createdAt: Date;
  updatedAt: Date;
}

// Further extension — add a status field
interface AuditedEntity<T> extends Entity<T> {
  deletedAt: Date | null;
  version: number;
}

// Concrete binding
type AuditedUser = AuditedEntity<{ name: string; email: string }>;
const u: AuditedUser = {
  id: 1,
  data: { name: 'Alice', email: 'alice@example.com' },
  createdAt: new Date(),
  updatedAt: new Date(),
  deletedAt: null,
  version: 1,
};

// Generic interface extending a non-generic interface
interface Named { name: string }

interface NamedCollection<T extends Named> {
  items: T[];
  findByName(name: string): T | undefined;
}
